function initLockLoadingScreen() {
    const wordObject = document.getElementById("lockStrokeWord");
    const statusTime = document.getElementById("lockStatusTime");
    const lockTime = document.getElementById("lockTime");

    if (!wordObject || !statusTime || !lockTime) return;

    const words = [
        { label: "你好", src: "assets/font-trails-vector-trace/nihao-vector-trace-full.svg", duration: 7000 },
        { label: "hello", src: "assets/font-trails-vector-trace/hello-vector-trace-full.svg", duration: 6200 },
        { label: "哈啰", src: "assets/font-trails-vector-trace/haluo-vector-trace-full.svg", duration: 7200 },
        { label: "hola", src: "assets/font-trails-vector-trace/hola-vector-trace-full.svg", duration: 6200 }
    ];

    let wordIndex = 0;

    function formatLockTime(date) {
        return date.toLocaleTimeString("zh-CN", {
            hour: "numeric",
            minute: "2-digit",
            hour12: false
        });
    }

    function updateLockTime() {
        const time = formatLockTime(new Date());
        statusTime.textContent = time;
        lockTime.textContent = time;
    }

    function showLockWord() {
        const word = words[wordIndex];
        wordObject.setAttribute("aria-label", word.label);
        wordObject.data = word.src;
    }

    function nextLockWord() {
        wordObject.classList.add("is-switching");
        window.setTimeout(() => {
            wordIndex = (wordIndex + 1) % words.length;
            showLockWord();
            wordObject.classList.remove("is-switching");
            window.setTimeout(nextLockWord, words[wordIndex].duration);
        }, 230);
    }

    showLockWord();
    updateLockTime();
    window.setInterval(updateLockTime, 1000);
    window.setTimeout(nextLockWord, words[wordIndex].duration);
}
        // --- [REFACTORED] IndexedDB Manager ---
                // --- [REFACTORED & ROBUST] IndexedDB Manager (v3) ---
        const dbManager = {
            db: null,
            dbName: 'JRSY_DB_V2',
            dbVersion: 23,
            stores: [
                'friends', 'chatHistories', 'diaries', 'worldBooks', 'worldBookFolders', 
                'favorites', 'moments', 'playlist', 'appSettings', 'apiSettings', 'customEmojis',
                'memories', 'openingStatements' , 'writingStyles', 'skits', 'forumPosts' , 'forumRules', 'forumLikes' , 'bubbleCssPresets', 'stickerGroups','interfaceCssPresets', 'apiPresets', 'cloneApiSettings', 'offlineContentPresets',
        'voiceAudioCache' , 'fontPresets', 'offlineCssPresets' , 'gameApiSettings' , 'summaryPrompts' , 'babies', 'babyChats'
            ],

            // 核心修改：初始化函数现在负责检查和重新连接
            init() {
                return new Promise((resolve, reject) => {
                    // 如果连接存在并且没有被关闭，就直接使用
                    if (this.db && this.db.version) {
                        return resolve(this.db);
                    }
                    console.log('数据库连接已关闭或未初始化，正在重新连接...');

                    const request = indexedDB.open(this.dbName, this.dbVersion);

                    request.onerror = (event) => {
                        console.error('IndexedDB error:', request.error);
                        reject('IndexedDB error: ' + request.error);
                    };

                    request.onsuccess = (event) => {
                        this.db = event.target.result;
                        console.log('数据库连接成功。');

                        // 关键！监听意外关闭事件
                        this.db.onclose = () => {
                            console.warn('数据库连接被意外关闭了！');
                            this.db = null; // 将连接状态清空，以便下次能重新连接
                        };
                        
                        resolve(this.db);
                    };

                    request.onupgradeneeded = (event) => {
                        console.log('正在升级数据库...');
                        const db = event.target.result;
                        this.stores.forEach(storeName => {
                            if (!db.objectStoreNames.contains(storeName)) {
                                if (storeName === 'chatHistories') {
                                    db.createObjectStore(storeName, { keyPath: 'friendId' });
                                } else if (storeName === 'appSettings' || storeName === 'apiSettings') {
                                    db.createObjectStore(storeName, { keyPath: 'id' });
                                } else {
                                    db.createObjectStore(storeName, { keyPath: 'id', autoIncrement: true });
                                }
                                console.log(`Object store '${storeName}' created.`);
                            }
                        });
                    };
                });
            },

            // 核心修改：所有操作前都调用 this.init()
            set(storeName, data) {
                return this.init().then(db => new Promise((resolve, reject) => {
                    const transaction = db.transaction(storeName, 'readwrite');
                    const store = transaction.objectStore(storeName);
                    const request = store.put(data);
                    request.onsuccess = () => resolve(request.result);
                    request.onerror = (event) => reject(`在 ${storeName} 中设置数据失败: ` + event.target.error);
                }));
            },

            get(storeName, key) {
                return this.init().then(db => new Promise((resolve, reject) => {
                    const transaction = db.transaction(storeName, 'readonly');
                    const store = transaction.objectStore(storeName);
                    const request = store.get(key);
                    request.onsuccess = () => resolve(request.result);
                    request.onerror = (event) => reject(`从 ${storeName} 中获取数据失败: ` + event.target.error);
                }));
            },

            getAll(storeName) {
                return this.init().then(db => new Promise((resolve, reject) => {
                    const transaction = db.transaction(storeName, 'readonly');
                    const store = transaction.objectStore(storeName);
                    const request = store.getAll();
                    request.onsuccess = () => resolve(request.result);
                    request.onerror = (event) => reject(`从 ${storeName} 中获取所有数据失败: ` + event.target.error);
                }));
            },
            
            delete(storeName, key) {
                return this.init().then(db => new Promise((resolve, reject) => {
                    const transaction = db.transaction(storeName, 'readwrite');
                    const store = transaction.objectStore(storeName);
                    const request = store.delete(key);
                    request.onsuccess = () => resolve();
                    request.onerror = (event) => reject(`从 ${storeName} 中删除数据失败: ` + event.target.error);
                }));
            },

            clear(storeName) {
                return this.init().then(db => new Promise((resolve, reject) => {
                    const transaction = db.transaction(storeName, 'readwrite');
                    const store = transaction.objectStore(storeName);
                    const request = store.clear();
                    request.onsuccess = () => resolve();
                    request.onerror = (event) => reject(`清空 ${storeName} 失败: ` + event.target.error);
                }));
            }
        };

async function requestPersistentStorage() {
    if (navigator.storage && navigator.storage.persist) {
        const isPersisted = await navigator.storage.persisted();
        if (!isPersisted) {
            const result = await navigator.storage.persist();
            if (result) {
                console.log("已请求持久性存储并获得授权");
            } else {
                console.warn("请求持久性存储被拒绝");
            }
        } else {
            console.log("已经是持久性存储模式");
        }
    }
}
