    const inputForReset = document.getElementById('messageInput');
    if (inputForReset.value.trim() === 'reset my wallet') {
        userProfile.balance = 50000; 
        await saveData(); 
        showAlert('钱包余额已成功重置！'); 
        inputForReset.value = ''; 
        return; 
    }

    // 2. 获取输入内容
