// ▲▲▲ 替换到此结束 ▲▲▲
                  // 【【【V2.0 升级：引入带动态截断的智能总结读取器】】】
        const SUMMARY_TOKEN_LIMIT = 10000; // 设定一个总结内容的最大token预算，可以根据需要调整
        let historicalSummaries = '';
