        function openWorldBookBindingModal() {
    const friend = friends.find(f => f.id === currentChatFriendId);
    if (!friend) return;

    const container = document.getElementById('worldBookBindingList');
    container.innerHTML = '';
    const boundBookIds = new Set(friend.worldBookIds ||[]);
    const boundFolderIds = new Set(friend.boundFolderIds ||[]);

    // 1. 遍历并渲染所有的文件夹
    worldBookFolders.forEach(folder => {
        const isFolderChecked = boundFolderIds.has(folder.id);
        
        // 渲染文件夹本身
        const folderItem = document.createElement('div');
        folderItem.className = 'multi-select-item';
        folderItem.innerHTML = `
            <input type="checkbox" data-type="folder" id="wbf-${folder.id}" value="${folder.id}" ${isFolderChecked ? 'checked' : ''} onchange="toggleFolderBooks('${folder.id}', this.checked)">
            <label for="wbf-${folder.id}" style="font-weight: bold; color: #333;">📁 ${folder.name}</label>
        `;
        container.appendChild(folderItem);

        // 2. 查找并渲染属于该文件夹的子文件（世界书）
        const booksInFolder = worldBooks.filter(wb => wb.folderId === folder.id);
        booksInFolder.forEach(book => {
            // 如果文件夹被选中，或者该书本身被单独选中，则勾选
            const isChecked = isFolderChecked || boundBookIds.has(book.id);
            const item = document.createElement('div');
            item.className = 'multi-select-item';
            item.style.paddingLeft = '25px'; // 缩进，体现层级关系
            item.innerHTML = `
                <input type="checkbox" data-type="book" class="wbb-child-of-${folder.id}" id="wb-${book.id}" value="${book.id}" ${isChecked ? 'checked' : ''} onchange="checkFolderStatus('${folder.id}')">
                <label for="wb-${book.id}" style="color: #666;">📄 ${book.name}</label>
            `;
            container.appendChild(item);
        });
    });
    
    // 3. 渲染没有被放进任何文件夹的“未分类世界书”
    const uncategorizedBooks = worldBooks.filter(wb => !wb.folderId || !worldBookFolders.some(f => f.id === wb.folderId));
    if (uncategorizedBooks.length > 0) {
        // 添加一个分割标题
        const uncatHeader = document.createElement('div');
        uncatHeader.style.cssText = 'padding: 10px 0 5px 0; color: #999; font-size: 12px; font-weight: bold;';
        uncatHeader.innerHTML = '未分类世界书';
        container.appendChild(uncatHeader);

        uncategorizedBooks.forEach(book => {
            const isChecked = boundBookIds.has(book.id);
            const item = document.createElement('div');
            item.className = 'multi-select-item';
            item.innerHTML = `
                <input type="checkbox" data-type="book" id="wb-${book.id}" value="${book.id}" ${isChecked ? 'checked' : ''}>
                <label for="wb-${book.id}">📄 ${book.name}</label>
            `;
            container.appendChild(item);
        });
    }

    if (container.innerHTML === '') {
         container.innerHTML = '<div style="color: #999; text-align: center; padding: 20px;">暂无世界书或文件夹可绑定</div>';
    }
    document.getElementById('worldBookBindingModal').classList.add('show');
}
        
        function closeWorldBookBindingModal() {
            document.getElementById('worldBookBindingModal').classList.remove('show');
        }
        
        async function confirmWorldBookBinding() {
    const friend = friends.find(f => f.id === currentChatFriendId);
    if (!friend) return;
    
    // 收集独立选中的世界书
    const selectedBooks =[];
    document.querySelectorAll('#worldBookBindingList input[data-type="book"]:checked').forEach(checkbox => selectedBooks.push(checkbox.value));
    friend.worldBookIds = selectedBooks;
    
    // 收集选中的文件夹
    const selectedFolders = [];
    document.querySelectorAll('#worldBookBindingList input[data-type="folder"]:checked').forEach(checkbox => selectedFolders.push(checkbox.value));
    friend.boundFolderIds = selectedFolders;
    
    // 【关键修复】确保写入数据库，永久生效
    await saveData(); 
    
    showAlert('绑定成功！');
    closeWorldBookBindingModal();
}

