            contentHTML = `<div class="sim-detail-content"><h3>${detailItem.title}</h3><div class="sim-list-meta">${detailItem.datetime}</div><hr><p>${(detailItem.content || '').replace(/\n/g, '<br>')}</p></div>`; 
