function getAuthorById(authorId) {
    if (!authorId) return { id: 'unknown', name: '未知', avatar: '?' };
    if (authorId === userProfile.id) return userProfile;

    // 1. 先在好友列表里找
    const friend = friends.find(f => f.id === authorId);
    if (friend) return friend;

    // --- 【核心修复】新增：检查是不是当前正在查看的临时NPC ---
    if (tempNpcData && tempNpcData.id === authorId) {
        return tempNpcData;
    }
    // --- 修复结束 ---

    // 2. 如果是 NPC ID (以 npc_ 开头)，去分组里找 (保持原逻辑)
    if (authorId.startsWith('npc_')) {
        for (const group of momentGroups) {
            if (group.npcs) {
                const npc = group.npcs.find(n => n.id === authorId);
                if (npc) {
                    return {
                        id: npc.id,
                        name: npc.name,
                        avatar: npc.name[0],
                        avatarImage: '', 
                        role: npc.role
                    };
                }
            }
        }
    }

    // 3. 兜底
    return { id: authorId, name: '未知用户', avatar: '?' };
}

        /**
 * [V7 全功能复活版] 主动消息生成逻辑
 * 1. 深度上下文：读取最近50条记录
 * 2. 情报注入：世界书 + 长期记忆
 * 3. 动作工具箱：完整复活所有交互动作
 * 4. 逻辑控制：严禁查岗，应用自定义温度
 */
async function generateMissedMessages(friendId) {
    const friendIdForThisRequest = friendId;
    const friend = friends.find(f => f.id === friendIdForThisRequest);

    if (!friend || !friend.proactiveMessageDebt || friend.proactiveMessageDebt === 0) {
        renderInitialMessages();
        return;
    }

    // 1. 环境与设置
    const settings = await dbManager.get('apiSettings', 'settings') || {};
    const customTemp = parseFloat(settings.apiTemperature) || 0.9;
    const activePersona = userPersonas.find(p => p.id === friend.activeUserPersonaId) || userProfile;

    // 2. 收集情报：50条聊天 + 世界书 + 长期记忆
    const history = (chatHistories[friendIdForThisRequest] || []).slice(-50);
    const chatContext = history.map(m => {
        const senderName = m.type === 'sent' ? activePersona.name : friend.name;
        return `[${formatTimestampForAI(m.timestamp)}] ${senderName}: ${summarizeMessageContentForAI(m)}`;
    }).join('\n');

    let worldBookContext = '无';
    const allBoundBookIds = new Set(friend.worldBookIds || []);
    (friend.boundFolderIds || []).forEach(folderId => {
        worldBooks.forEach(wb => { if (wb.folderId === folderId) allBoundBookIds.add(wb.id); });
    });
    if (allBoundBookIds.size > 0) {
        worldBookContext = Array.from(allBoundBookIds).map(id => worldBooks.find(wb => wb.id === id)).filter(Boolean).map(wb => `[${wb.name}]: ${wb.content}`).join('\n\n');
    }

    let summaryContext = '无';
    const memories = (characterMemories[friendIdForThisRequest] || []);
    if (memories.length > 0) {
        summaryContext = memories.map(mem => mem.content).join('\n\n---\n\n');
    }

    // 3. 表情包授权 (只有角色被允许发这些名称的表情)
    const allowedGroupIds = [...new Set([...(globalStickerGroupIds || []), ...(friend.enabledStickerGroupIds || [])])];
    const availableEmojis = customEmojis.filter(e => allowedGroupIds.includes(e.groupId)).map(e => e.name).join('", "');

    // 4. 精简且带工具箱的 Prompt
    const prompt = `你是"${friend.name}"，人设：${friend.role}。好友："${activePersona.name}"。
你们已经很久没联系了（大约 ${friend.proactiveMessageDebt * proactiveMessagingSettings.interval} 分钟）。请以你的身份主动发几条消息。

【世界设定】: ${worldBookContext}
【长期记忆】: ${summaryContext}
【最近50条记录】:
${chatContext || '刚开始聊天'}

【指令】:
1. **生活感**: 请分享你此时的处境、心情、吐槽或对接之前的话题。严禁“在吗/报警/不回消息”等查岗言论。
2. **多模态**: 灵活使用下方工具箱。请分 ${Math.min(friend.proactiveMessageDebt + 1, 5)} 条消息发送。
3. **输出**: 必须返回纯净 JSON 数组 \`[]\`。

【动作工具箱】:
- 文字: {"type": "text", "content": "内容"}
- 语音: {"type": "voice", "content": "语音文字内容"}
- 表情(可用:["${availableEmojis}"]): {"type": "send_emoji", "data": {"name": "表情名"}}
- 图片: {"type": "image", "description": "画面详细描述"}
- 拍一拍: {"type": "pat_pat"}
- 转账: {"type": "transfer", "data": {"amount": 数字, "remark": "..."}}
- HTML卡片: {"type": "html_card", "content": "HTML代码"}`;

    aiReplyingSet.add(friendIdForThisRequest);
    document.getElementById('chatTitle').textContent = '对方正在输入...';

    try {
        const response = await fetch(`${settings.apiUrl}/chat/completions`, {
            method: 'POST',
            headers: { 'Authorization': `Bearer ${settings.apiKey}`, 'Content-Type': 'application/json' },
            body: JSON.stringify({
                model: settings.modelName,
                messages: [{ role: 'user', content: prompt }],
                temperature: customTemp,
                presence_penalty: 0.6
            })
        });

        const data = await response.json();
        const responseData = safelyParseAiResponse(data.choices[0].message.content);
        
        if (Array.isArray(responseData)) {
            for (const action of responseData) {
                let msgData = null;
                await new Promise(res => setTimeout(res, 1000 + Math.random() * 2000)); 

                // 执行动作解析
                switch (action.type) {
                    case 'text':
                    case 'voice':
                        if (action.content) {
                            const cleanText = action.content.replace(/\[.*?\]/g, '').trim();
                            if (cleanText) msgData = await saveChatMessage(friendIdForThisRequest, 'received', cleanText, '', friend.id, action.type);
                        }
                        break;
                    case 'send_emoji':
                        const validEmoji = customEmojis.find(e => e.name === action.data?.name && allowedGroupIds.includes(e.groupId));
                        if (validEmoji) {
                            msgData = await saveChatMessage(friendIdForThisRequest, 'received', validEmoji.url, '', friend.id, 'emoji');
                            msgData.emojiName = validEmoji.name;
                        }
                        break;
                    case 'image':
                        const placeholder = `data:image/svg+xml,${encodeURIComponent('<svg xmlns="http://www.w3.org/2000/svg" width="150" height="150"><rect width="100%" height="100%" fill="#eee"/><text x="50%" y="50%" text-anchor="middle">加载图片...</text></svg>')}`;
                        msgData = await saveChatMessage(friendIdForThisRequest, 'received', placeholder, '', friend.id, 'image');
                        msgData.imageDescription = action.description;
                        break;
                    case 'pat_pat':
                        const mySuffix = activePersona.patAction || '';
                        msgData = await saveChatMessage(friendIdForThisRequest, 'system', `"${friend.name}"拍了拍"你"${mySuffix}`, '', null, 'pat_pat');
                        break;
                    case 'transfer':
                        if (action.data?.amount > 0) {
                            msgData = await saveChatMessage(friendIdForThisRequest, 'received', JSON.stringify({amount: action.data.amount, remark: action.data.remark || ''}), '', friend.id, 'transfer_request');
                        }
                        break;
                    case 'html_card':
                        if (action.content) msgData = await saveChatMessage(friendIdForThisRequest, 'received', action.content, '', friend.id, 'html_card');
                        break;
                }

                if (msgData && friendIdForThisRequest === currentChatFriendId) {
                    if (isOfflineModeActive) renderOfflineHistory();
                    else addMessageToDOM(msgData, friend);
                    document.getElementById('chatMessages').scrollTop = document.getElementById('chatMessages').scrollHeight;
                    playMessageSound('received');
                } else if (msgData) {
                    showNotification(friend, "[收到一条消息]");
                    playMessageSound('received');
                }
            }
        }
    } catch (error) {
        console.error("主动消息失败:", error);
    } finally {
        friend.proactiveMessageDebt = 0; 
        await saveData();
        aiReplyingSet.delete(friendIdForThisRequest);
        if (currentChatFriendId === friendIdForThisRequest) {
            document.getElementById('chatTitle').textContent = friend.remark || friend.name;
        }
        updateFriendList(); 
    }
}

// 【【【这是一个全新的工具函数，请把它粘贴到<script>的末尾】】】
/**
 * 将ISO格式的时间字符串转换为AI可读的格式
 * @param {string} isoString - new Date().toISOString() 生成的时间字符串
 * @returns {string} 格式如 "YYYY-MM-DD HH:MM" 的字符串
 */
function formatTimestampForAI(isoString) {
    if (!isoString) return '';
    const date = new Date(isoString);
    const pad = (num) => num.toString().padStart(2, '0');
    
    const year = date.getFullYear();
    const month = pad(date.getMonth() + 1);
    const day = pad(date.getDate());
    const hours = pad(date.getHours());
    const minutes = pad(date.getMinutes());
    
    return `${year}-${month}-${day} ${hours}:${minutes}`;
}

