/**
 * [新增] 核心功能：删除指定的 CP 设定
 * @param {Event} event - 点击事件对象
 * @param {string} cpId - 要删除的CP ID
 */
async function doujinDeleteCp(event, cpId) {
    // 阻止事件冒泡，防止点击删除时错误触发“进入编辑页面”
    event.stopPropagation();

    // 弹出确认框防误删
    showConfirm('确定要删除这对CP吗？删除后将无法恢复。', async (confirmed) => {
        if (!confirmed) return;

        // 1. 从内存数组中过滤掉这条数据
        doujin_MOCK_CPS = doujin_MOCK_CPS.filter(cp => String(cp.id) !== String(cpId));

        // 2. 如果删除的刚好是目前全局设定(产粮用)的那个CP，将其重置置空
        if (String(doujin_cpRunConfig.cpId) === String(cpId)) {
            doujin_cpRunConfig.cpId = null;
        }

        // 3. 永久保存到 IndexedDB 数据库
        await saveData();

        // 4. 重新渲染列表刷新界面
        doujinRenderCpCards();

        // 提示用户成功
        showToast('CP已成功删除');
    });
}

